def solve(arg1: dict) -> dict:
    # Initialize a mock database for platforms and formats
    platforms = {}
    formats = {}

    # Helper functions
    def add_platform(platform_name):
        if platform_name in platforms:
            return {'status': 'error', 'message': 'Platform already exists.'}
        platforms[platform_name] = {'formats': []}
        return {'status': 'success', 'message': 'Platform added successfully.'}

    def delete_format(format_name):
        if format_name not in formats:
            return {'status': 'error', 'message': 'Format not found.'}
        del formats[format_name]
        return {'status': 'success', 'message': 'Format deleted successfully.'}

    def edit_platform(platform_name, new_name):
        if platform_name not in platforms or new_name in platforms:
            return {'status': 'error', 'message': 'Platform not found or new name already exists.'}
        platforms[new_name] = platforms.pop(platform_name)
        return {'status': 'success', 'message': 'Platform edited successfully.'}

    # Process input commands
    for command in arg1.get('commands', []):
        action = command.get('action')
        if action == 'add_platform':
            platform_name = command.get('platform_name')
            add_platform(platform_name)
        elif action == 'delete_format':
            format_name = command.get('format_name')
            delete_format(format_name)
        elif action == 'edit_platform':
            platform_name = command.get('platform_name')
            new_name = command.get('new_name')
            edit_platform(platform_name, new_name)

    return {'platforms': platforms, 'formats': formats}
